  params: Promise<{
    participant_id: string;
  }>;
};

type ParticipantPageData = {
  participant_id: string;
  participant_name: string;
  session_id: string;
  session_location: string;
  session_date: string;
  session_time: string;
  class_name: string;
  qr_code_data: string;
